from __future__ import annotations
import pandas as pd
import structlog
from ..eval_engine import FeatureEvaluator

log = structlog.get_logger()

# %% auto #0
__all__ = ['log', 'FSCGenomewideEvaluator']

# %% ../../nbs/features/11b_fsc_genomewide.ipynb #e0ade985
class FSCGenomewideEvaluator(FeatureEvaluator):
    """Extracts GC-corrected log2 fragment size category signals from genomewide bins.

    Only bins with read coverage (total > 0) are included in aggregation.
    Genomewide panels typically cover ~93% of bins, but the filter ensures
    uncovered bins don't contribute noise to summary statistics.
    """

    name = "FSCGenomewide"
    source_file = ".FSC.parquet"
    tier = 1
    category = "fragmentation"

    def extract(self, df: pd.DataFrame) -> dict[str, float]:
        extracted = {}
        try:
            if df.empty:
                return extracted

            # Filter to bins with actual read coverage
            if "total" in df.columns:
                n_total = len(df)
                df = df[df["total"] > 0]
                extracted["n_covered_bins"] = len(df)
                extracted["n_total_bins"] = n_total
                if df.empty:
                    log.warning(
                        "no_covered_bins",
                        evaluator=self.name,
                        total_bins=n_total,
                    )
                    return extracted

            cols = set(df.columns)
            log2_cols = sorted(c for c in cols if c.endswith("_log2"))

            # Global median over covered bins
            for col in log2_cols:
                extracted[f"global_{col}_median"] = float(df[col].median())

            # Per-chromosome aggregates over covered bins
            if "chrom" in cols:
                chroms = [f"chr{i}" for i in range(1, 23)] + ["chrX", "chrY"]
                for chrom in chroms:
                    sub = df[df["chrom"] == chrom]
                    if sub.empty:
                        continue
                    for col in log2_cols:
                        extracted[f"{chrom}_{col}_median"] = float(sub[col].median())

            return extracted
        except Exception as e:
            log.exception("extraction_failed", evaluator=self.name, error=str(e))
            return {}
